import React from 'react'
import ReactApexChart from 'react-apexcharts'
import ApexCharts from 'apexcharts'
import './styles.css'

// Shared by the vanilla-js, React and Vue builds. Two datasets to show off both
// layouts: the House seat split (grouped clusters) and a single population with
// a highlighted minority (packed blob). The live control state lives in each
// format's own wiring below.
var DATASETS = {
  house: {
    values: [276, 266, 3],
    labels: ['Republican', 'Democrat', 'Independent'],
    colors: ['#EB4D4B', '#2E86DE', '#95A5A6'],
    layout: 'grouped',
  },
  gender: {
    values: [65, 835],
    labels: ['Female', 'Male'],
    colors: ['#EE5A8F', '#1AA5A0'],
    layout: 'packed',
  },
}

function randomHouse() {
  var r = Math.floor(Math.random() * 120) + 200
  var d = Math.floor(Math.random() * 120) + 200
  var i = Math.floor(Math.random() * 12)
  return [r, d, i]
}

function setActive(id) {
  document
    .querySelectorAll('.actions button[data-dataset]')
    .forEach(function (btn) {
      btn.classList.toggle('active', btn.getAttribute('data-dataset') === id)
    })
}

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [276, 266, 3],
    options: {
      chart: {
        id: 'unitChart',
        type: 'unit',
        height: 420,
        animations: {
          enabled: true,
          speed: 900,
        },
      },
      labels: ['Republican', 'Democrat', 'Independent'],
      colors: ['#EB4D4B', '#2E86DE', '#95A5A6'],
      plotOptions: {
        unit: {
          layout: 'grouped',
          shape: 'circle',
          size: 'auto',
          clusterLabels: {
            show: true,
          },
        },
      },
      legend: {
        position: 'bottom',
      },
    },
  })

  React.useEffect(() => {
    // The react-apexcharts wrapper owns the render, so reach the live instance by
    // its chart.id, then wire the controls. (DATASETS/randomHouse/setActive live
    // in the shared head script.) updateOptions drives the instance directly, so
    // no React state changes under it.
    let chart
    let current = 'house'

    const timer = window.setInterval(() => {
      chart = ApexCharts.getChartByID('unitChart')
      if (!chart) return
      window.clearInterval(timer)

      setActive(current)

      document
        .querySelectorAll('.actions button[data-dataset]')
        .forEach((btn) => {
          btn.addEventListener('click', () => {
            const id = btn.getAttribute('data-dataset')
            if (id === current) return
            current = id
            setActive(current)
            const ds = DATASETS[id]
            chart.updateOptions({
              colors: ds.colors,
              labels: ds.labels,
              plotOptions: { unit: { layout: ds.layout } },
              series: ds.values,
            })
          })
        })

      document.querySelector('#shuffle').addEventListener('click', () => {
        if (current !== 'house') return
        chart.updateSeries(randomHouse())
      })
    }, 50)

    return () => window.clearInterval(timer)
  }, [])

  return (
    <div>
      <div className="wrap">
        <h1>Unit chart (dot cluster)</h1>
        <p>
          Every member is one dot. Dots pack into an organic disc with a
          phyllotaxis (sunflower) spiral and glide into place on each update.
          Switch datasets to see the grouped clusters re-form as a single packed
          blob with the minority nested in the centre.
        </p>

        <div className="chart-wrap">
          <div id="chart">
            <ReactApexChart
              options={state.options}
              series={state.series}
              type="unit"
              height={420}
            />
          </div>
        </div>

        <div className="actions">
          <button data-dataset="house">House seats (grouped)</button>
          <button data-dataset="gender">Population (packed)</button>
        </div>

        <div className="actions">
          <button id="shuffle">Shuffle seats</button>
        </div>
      </div>
    </div>
  )
}

export default ApexChart

